update student
name = #{name}, no = #{no}, gender = #{gender}, phone = #{phone}, id_card = #{idCard}, is_college = #{isCollege}, clazz_id = #{clazzId},
address = #{address}, degree = #{degree}, graduation_date = #{graduationDate}, update_time = #{updateTime}
